const body = $input.first().json.body;
console.log('[Extraire message] Body:', JSON.stringify(body, null, 2));

const sender = body.From || '';
const message = body.Body || '';
const numMedia = parseInt(body.NumMedia || '0');
const mediaUrl = body.MediaUrl0 || null;
const mediaType = body.MediaContentType0 || null;

console.log('[Extraire message] Sender:', sender, '| Message:', message);

return [{ json: { sender, message, numMedia, mediaUrl, mediaType, timestamp: new Date().toISOString() } }];

const items = $input.all();
const raw = items[0].json.output || items[0].json.text || '';
console.log('[Détecter signal] Réponse brute (100 chars):', raw.substring(0, 100));

const reclamationMatch = raw.match(/\[\[RECLAMATION\]\](.*?)\[\[\/RECLAMATION\]\]/s);
const escaladeMatch = raw.match(/\[\[ESCALADE\]\](.*?)\[\[\/ESCALADE\]\]/s);

let signal = null;
let signalType = 'none';

if (escaladeMatch) {
  try {
    signal = JSON.parse(escaladeMatch[1].trim());
    signalType = 'escalade';
    console.log('[Détecter signal] ESCALADE:', JSON.stringify(signal));
  } catch(e) { console.error('[Détecter signal] Erreur parse ESCALADE:', e.message); }
} else if (reclamationMatch) {
  try {
    signal = JSON.parse(reclamationMatch[1].trim());
    signalType = 'reclamation';
    console.log('[Détecter signal] RECLAMATION:', JSON.stringify(signal));
  } catch(e) { console.error('[Détecter signal] Erreur parse RECLAMATION:', e.message); }
}

const cleanMessage = raw
  .replace(/\[\[RECLAMATION\]\].*?\[\[\/RECLAMATION\]\]/s, '')
  .replace(/\[\[ESCALADE\]\].*?\[\[\/ESCALADE\]\]/s, '')
  .trim();

console.log('[Détecter signal] Type:', signalType, '| Propre:', cleanMessage.substring(0, 80));

return [{ json: { cleanMessage, signalType, signal, sender: $('Extraire message').item.json.sender } }];

const laravelResponse = $input.first().json;
console.log('[Injecter autoRef] Réponse Laravel:', JSON.stringify(laravelResponse, null, 2));

const autoRef = laravelResponse.reference || laravelResponse.autoRef || laravelResponse.id || ('SC-' + Date.now());
console.log('[Injecter autoRef] Ref:', autoRef);

const rawMessage = $('Détecter signal').item.json.cleanMessage;
const sender = $('Détecter signal').item.json.sender;
const finalMessage = rawMessage.replace('{autoRef}', autoRef);

return [{ json: { finalMessage, sender, autoRef } }];
